const body = $json.body || {};
const binary = $binary || {};
const fileKey = binary.pdf_file ? 'pdf_file' : (binary.data ? 'data' : null);

let parsedPdfMetrics = {};
let parsedFinancialDetails = {};

if (body.pdf_metrics_json) {
  try {
    parsedPdfMetrics = JSON.parse(body.pdf_metrics_json);
  } catch (e) {
    parsedPdfMetrics = {
      parse_error: String(e),
      raw_value: body.pdf_metrics_json
    };
  }
}

if (body.financial_details_json) {
  try {
    parsedFinancialDetails = JSON.parse(body.financial_details_json);
  } catch (e) {
    parsedFinancialDetails = {
      parse_error: String(e),
      raw_value: body.financial_details_json
    };
  }
}

function getNested(obj, path, fallback = '') {
  try {
    let cur = obj;
    for (const p of path) {
      if (cur == null || !(p in cur)) return fallback;
      cur = cur[p];
    }
    return cur ?? fallback;
  } catch (e) {
    return fallback;
  }
}

// --- agentic_flow.py payload support ---
// The Flask UI posts JSON like: { sent_at, source, result }
if (body && body.result && typeof body.result === 'object') {
  const result = body.result || {};
  const orgs = result.organisations || {};

  let recommended = result.recommended_organisation || '';
  if (!recommended && orgs && typeof orgs === 'object') {
    const keys = Object.keys(orgs);
    if (keys.length) {
      keys.sort((a, b) => {
        const A = orgs[a] || {};
        const B = orgs[b] || {};
        const ap = Number(A.avg_perf_score || 0);
        const bp = Number(B.avg_perf_score || 0);
        if (bp !== ap) return bp - ap;
        const ae = Number(A.avg_extraction_score || 0);
        const be = Number(B.avg_extraction_score || 0);
        if (be !== ae) return be - ae;
        const ac = Number(A.pdf_count || 0);
        const bc = Number(B.pdf_count || 0);
        return bc - ac;
      });
      recommended = keys[0] || '';
    }
  }

  let runner_up = '';
  try {
    const names = Object.keys(orgs || {});
    const others = names.filter((o) => o && o !== recommended);
    if (recommended && others.length) {
      others.sort((a, b) => Number((orgs[b] || {}).avg_perf_score || 0) - Number((orgs[a] || {}).avg_perf_score || 0));
      runner_up = others[0] || '';
    }
  } catch (e) {}

  const insights = result.insights || {};
  const reasons = Array.isArray(insights.recommendation_reasons) ? insights.recommendation_reasons : [];
  const sw = insights.strengths_weaknesses || {};
  const rec_sw = (recommended && sw && typeof sw === 'object') ? (sw[recommended] || {}) : {};
  const strengths = Array.isArray(rec_sw.strengths) ? rec_sw.strengths : [];
  const weaknesses = Array.isArray(rec_sw.weaknesses) ? rec_sw.weaknesses : [];

  const recOrg = (recommended && orgs && typeof orgs === 'object') ? (orgs[recommended] || {}) : {};
  const metrics = (recOrg.metrics && typeof recOrg.metrics === 'object') ? recOrg.metrics : {};

  const sentAt = body.sent_at || new Date().toISOString();
  const source = body.source || 'agentic_flow_ui';
  const pdfNames = Array.isArray(result.results)
    ? result.results.map((x) => (x && (x.pdf_path || x.filename)) ? (x.pdf_path || x.filename) : '').filter(Boolean).join(' | ')
    : '';

  return [{
    json: {
      ok: true,
      analysis_type: 'agentic_flow_result',
      message: 'agentic_flow analysis received successfully in n8n.',
      receivedAt: sentAt,
      ingest_status: 'received_agentic_flow',
      source: source,

      company_name: body.company_name || '',
      quarter: body.quarter || '',
      industry: body.industry || '',
      file_name: pdfNames,

      recommended_organisation: recommended || '',
      runner_up: runner_up || '',
      recommendation_reasons: reasons.join(' | '),
      strengths: strengths.join(' | '),
      weaknesses: weaknesses.join(' | '),
      pdf_count: String(result.pdf_count ?? ''),

      ratio_net_profit_margin: (metrics.net_profit_margin ?? ''),
      ratio_roa: (metrics.roa ?? ''),
      ratio_roe: (metrics.roe ?? ''),
      ratio_cost_to_income: (metrics.cost_to_income ?? ''),
      ratio_npl_ratio: (metrics.asset_quality ?? ''),
      ratio_loan_to_deposit: (metrics.loan_to_deposit ?? ''),

      pdf_metrics_json: JSON.stringify({ sent_at: sentAt, source: source }),
      financial_details_json: JSON.stringify(result),
    }
  }];
}

if (!fileKey) {
  return [{
    json: {
      ok: false,
      message: 'No PDF found. Send multipart/form-data with file field pdf_file or data.',
      receivedAt: new Date().toISOString(),
      company_name: body.company_name || '',
      quarter: body.quarter || '',
      industry: body.industry || '',
      original_field_name: '',
      file_name: '',
      mime_type: '',
      file_extension: '',
      file_size: '',
      ingest_status: 'failed_validation',

      pdf_sha256: body.pdf_sha256 || parsedPdfMetrics.sha256 || '',
      pdf_size_bytes: body.pdf_size_bytes || parsedPdfMetrics.file_size_bytes || '',
      pdf_page_count: body.pdf_page_count || parsedPdfMetrics.page_count || '',
      pdf_word_count_sampled: body.pdf_word_count_sampled || getNested(parsedPdfMetrics, ['text_stats', 'word_count'], ''),
      pdf_metrics_json: body.pdf_metrics_json || '',
      metrics_ingested_at: parsedPdfMetrics.ingested_at || '',
      metrics_pdf_signature_ok: String(parsedPdfMetrics.pdf_signature_ok ?? ''),
      metrics_chars: String(getNested(parsedPdfMetrics, ['text_stats', 'chars'], '')),
      metrics_nonempty_line_count: String(getNested(parsedPdfMetrics, ['text_stats', 'nonempty_line_count'], '')),
      metrics_number_token_count: String(getNested(parsedPdfMetrics, ['text_stats', 'number_token_count'], '')),
      metrics_email_count: String(getNested(parsedPdfMetrics, ['text_stats', 'email_count'], '')),
      metrics_url_count: String(getNested(parsedPdfMetrics, ['text_stats', 'url_count'], '')),
      metrics_currency_mention_count: String(getNested(parsedPdfMetrics, ['text_stats', 'currency_mention_count'], '')),
      metrics_image_count_in_sampled_pages: String(parsedPdfMetrics.image_count_in_sampled_pages ?? ''),
      metrics_sampled_page_count: String(parsedPdfMetrics.sampled_page_count ?? ''),
      metrics_preview_text: parsedPdfMetrics.preview_text || '',
      metrics_metadata_json: JSON.stringify(parsedPdfMetrics.metadata || {}),

      financial_details_json: body.financial_details_json || '',
      fin_extracted_at: parsedFinancialDetails.extracted_at || '',
      fin_sampled_page_count: String(parsedFinancialDetails.sampled_page_count ?? ''),
      fin_units_currency: getNested(parsedFinancialDetails, ['units', 'currency'], ''),
      fin_units_label: getNested(parsedFinancialDetails, ['units', 'units_label'], ''),
      fin_found_items_count: String(getNested(parsedFinancialDetails, ['extraction_quality', 'found_items_count'], '')),
      fin_has_income_statement: String(getNested(parsedFinancialDetails, ['extraction_quality', 'has_income_statement'], '')),
      fin_has_balance_sheet: String(getNested(parsedFinancialDetails, ['extraction_quality', 'has_balance_sheet'], '')),

      income_total_operating_income: body.income_total_operating_income || getNested(parsedFinancialDetails, ['income_statement', 'total_operating_income', 'current'], ''),
      income_profit_for_period: body.income_profit_for_period || getNested(parsedFinancialDetails, ['income_statement', 'profit_for_period', 'current'], ''),
      bs_total_assets: body.bs_total_assets || getNested(parsedFinancialDetails, ['balance_sheet', 'total_assets'], ''),
      ratio_roa: body.ratio_roa || getNested(parsedFinancialDetails, ['computed_ratios', 'roa', 'value'], ''),
      ratio_roe: body.ratio_roe || getNested(parsedFinancialDetails, ['computed_ratios', 'roe', 'value'], ''),
      ratio_cost_to_income: body.ratio_cost_to_income || getNested(parsedFinancialDetails, ['computed_ratios', 'cost_to_income', 'value'], ''),
      ratio_npl_ratio: body.ratio_npl_ratio || getNested(parsedFinancialDetails, ['computed_ratios', 'npl_ratio', 'value'], ''),
      ratio_coverage_ratio: body.ratio_coverage_ratio || getNested(parsedFinancialDetails, ['computed_ratios', 'coverage_ratio', 'value'], ''),
      ratio_loan_to_deposit: body.ratio_loan_to_deposit || getNested(parsedFinancialDetails, ['computed_ratios', 'loan_to_deposit', 'value'], ''),

      income_net_interest_income: getNested(parsedFinancialDetails, ['income_statement', 'net_interest_income', 'current'], ''),
      income_operating_profit_before_impairment: getNested(parsedFinancialDetails, ['income_statement', 'operating_profit_before_impairment', 'current'], ''),
      income_profit_before_tax: getNested(parsedFinancialDetails, ['income_statement', 'profit_before_tax', 'current'], ''),
      income_taxation: getNested(parsedFinancialDetails, ['income_statement', 'taxation', 'current'], ''),
      income_eps: getNested(parsedFinancialDetails, ['income_statement', 'eps', 'current'], ''),
      income_operating_expenses: getNested(parsedFinancialDetails, ['income_statement', 'operating_expenses', 'current'], ''),
      bs_gross_loans: getNested(parsedFinancialDetails, ['balance_sheet', 'gross_loans'], ''),
      bs_deposits: getNested(parsedFinancialDetails, ['balance_sheet', 'deposits'], ''),
      bs_npls: getNested(parsedFinancialDetails, ['balance_sheet', 'npls'], ''),
      bs_ecl: getNested(parsedFinancialDetails, ['balance_sheet', 'ecl'], ''),
      bs_equity: getNested(parsedFinancialDetails, ['balance_sheet', 'equity'], ''),
      ratio_net_profit_margin: getNested(parsedFinancialDetails, ['computed_ratios', 'net_profit_margin', 'value'], ''),
      ratio_pre_impairment_margin: getNested(parsedFinancialDetails, ['computed_ratios', 'pre_impairment_margin', 'value'], ''),
      ratio_tax_rate: getNested(parsedFinancialDetails, ['computed_ratios', 'tax_rate', 'value'], ''),
      ratio_ecl_to_gross_loans: getNested(parsedFinancialDetails, ['computed_ratios', 'ecl_to_gross_loans', 'value'], ''),
      reported_roa_percent: getNested(parsedFinancialDetails, ['reported_ratios', 'roa', 'as_percent'], ''),
      reported_roe_percent: getNested(parsedFinancialDetails, ['reported_ratios', 'roe', 'as_percent'], '')
    }
  }];
}

const file = binary[fileKey];

return [{
  json: {
    ok: true,
    message: 'PDF received successfully in n8n.',
    receivedAt: new Date().toISOString(),
    company_name: body.company_name || '',
    quarter: body.quarter || '',
    industry: body.industry || '',
    original_field_name: fileKey,
    file_name: file.fileName || '',
    mime_type: file.mimeType || '',
    file_extension: file.fileExtension || '',
    file_size: file.fileSize || '',
    ingest_status: 'received',

    pdf_sha256: body.pdf_sha256 || parsedPdfMetrics.sha256 || '',
    pdf_size_bytes: body.pdf_size_bytes || parsedPdfMetrics.file_size_bytes || file.fileSize || '',
    pdf_page_count: body.pdf_page_count || parsedPdfMetrics.page_count || '',
    pdf_word_count_sampled: body.pdf_word_count_sampled || getNested(parsedPdfMetrics, ['text_stats', 'word_count'], ''),
    pdf_metrics_json: body.pdf_metrics_json || '',
    metrics_ingested_at: parsedPdfMetrics.ingested_at || '',
    metrics_pdf_signature_ok: String(parsedPdfMetrics.pdf_signature_ok ?? ''),
    metrics_chars: String(getNested(parsedPdfMetrics, ['text_stats', 'chars'], '')),
    metrics_nonempty_line_count: String(getNested(parsedPdfMetrics, ['text_stats', 'nonempty_line_count'], '')),
    metrics_number_token_count: String(getNested(parsedPdfMetrics, ['text_stats', 'number_token_count'], '')),
    metrics_email_count: String(getNested(parsedPdfMetrics, ['text_stats', 'email_count'], '')),
    metrics_url_count: String(getNested(parsedPdfMetrics, ['text_stats', 'url_count'], '')),
    metrics_currency_mention_count: String(getNested(parsedPdfMetrics, ['text_stats', 'currency_mention_count'], '')),
    metrics_image_count_in_sampled_pages: String(parsedPdfMetrics.image_count_in_sampled_pages ?? ''),
    metrics_sampled_page_count: String(parsedPdfMetrics.sampled_page_count ?? ''),
    metrics_preview_text: parsedPdfMetrics.preview_text || '',
    metrics_metadata_json: JSON.stringify(parsedPdfMetrics.metadata || {}),

    financial_details_json: body.financial_details_json || '',
    fin_extracted_at: parsedFinancialDetails.extracted_at || '',
    fin_sampled_page_count: String(parsedFinancialDetails.sampled_page_count ?? ''),
    fin_units_currency: getNested(parsedFinancialDetails, ['units', 'currency'], ''),
    fin_units_label: getNested(parsedFinancialDetails, ['units', 'units_label'], ''),
    fin_found_items_count: String(getNested(parsedFinancialDetails, ['extraction_quality', 'found_items_count'], '')),
    fin_has_income_statement: String(getNested(parsedFinancialDetails, ['extraction_quality', 'has_income_statement'], '')),
    fin_has_balance_sheet: String(getNested(parsedFinancialDetails, ['extraction_quality', 'has_balance_sheet'], '')),

    income_total_operating_income: body.income_total_operating_income || getNested(parsedFinancialDetails, ['income_statement', 'total_operating_income', 'current'], ''),
    income_profit_for_period: body.income_profit_for_period || getNested(parsedFinancialDetails, ['income_statement', 'profit_for_period', 'current'], ''),
    bs_total_assets: body.bs_total_assets || getNested(parsedFinancialDetails, ['balance_sheet', 'total_assets'], ''),
    ratio_roa: body.ratio_roa || getNested(parsedFinancialDetails, ['computed_ratios', 'roa', 'value'], ''),
    ratio_roe: body.ratio_roe || getNested(parsedFinancialDetails, ['computed_ratios', 'roe', 'value'], ''),
    ratio_cost_to_income: body.ratio_cost_to_income || getNested(parsedFinancialDetails, ['computed_ratios', 'cost_to_income', 'value'], ''),
    ratio_npl_ratio: body.ratio_npl_ratio || getNested(parsedFinancialDetails, ['computed_ratios', 'npl_ratio', 'value'], ''),
    ratio_coverage_ratio: body.ratio_coverage_ratio || getNested(parsedFinancialDetails, ['computed_ratios', 'coverage_ratio', 'value'], ''),
    ratio_loan_to_deposit: body.ratio_loan_to_deposit || getNested(parsedFinancialDetails, ['computed_ratios', 'loan_to_deposit', 'value'], ''),

    income_net_interest_income: getNested(parsedFinancialDetails, ['income_statement', 'net_interest_income', 'current'], ''),
    income_operating_profit_before_impairment: getNested(parsedFinancialDetails, ['income_statement', 'operating_profit_before_impairment', 'current'], ''),
    income_profit_before_tax: getNested(parsedFinancialDetails, ['income_statement', 'profit_before_tax', 'current'], ''),
    income_taxation: getNested(parsedFinancialDetails, ['income_statement', 'taxation', 'current'], ''),
    income_eps: getNested(parsedFinancialDetails, ['income_statement', 'eps', 'current'], ''),
    income_operating_expenses: getNested(parsedFinancialDetails, ['income_statement', 'operating_expenses', 'current'], ''),
    bs_gross_loans: getNested(parsedFinancialDetails, ['balance_sheet', 'gross_loans'], ''),
    bs_deposits: getNested(parsedFinancialDetails, ['balance_sheet', 'deposits'], ''),
    bs_npls: getNested(parsedFinancialDetails, ['balance_sheet', 'npls'], ''),
    bs_ecl: getNested(parsedFinancialDetails, ['balance_sheet', 'ecl'], ''),
    bs_equity: getNested(parsedFinancialDetails, ['balance_sheet', 'equity'], ''),
    ratio_net_profit_margin: getNested(parsedFinancialDetails, ['computed_ratios', 'net_profit_margin', 'value'], ''),
    ratio_pre_impairment_margin: getNested(parsedFinancialDetails, ['computed_ratios', 'pre_impairment_margin', 'value'], ''),
    ratio_tax_rate: getNested(parsedFinancialDetails, ['computed_ratios', 'tax_rate', 'value'], ''),
    ratio_ecl_to_gross_loans: getNested(parsedFinancialDetails, ['computed_ratios', 'ecl_to_gross_loans', 'value'], ''),
    reported_roa_percent: getNested(parsedFinancialDetails, ['reported_ratios', 'roa', 'as_percent'], ''),
    reported_roe_percent: getNested(parsedFinancialDetails, ['reported_ratios', 'roe', 'as_percent'], '')
  },
  binary: {
    [fileKey]: file
  }
}];
